class CountIntervals {
public:
    CountIntervals() {
        intervals = new vector<pair<int, int>>();
    }

    void add(int left, int right) {
        if (intervals->empty()) {
            intervals->push_back({left, right});
            return;
        }

        int n = intervals->size();
        for (int i = 0; i < n; i++) {
            if (right < (*intervals)[i].first) {
                intervals->insert(intervals->begin() + i, {left, right});
                return;
            } else if (left > (*intervals)[i].second) {
                continue;
            } else {
                left = min(left, (*intervals)[i].first);
                right = max(right, (*intervals)[i].second);
                intervals->erase(intervals->begin() + i);
                i--;
                n--;
            }
        }
        intervals->push_back({left, right});
    }

    int count() {
        int count = 0;
        for (auto interval : *intervals) {
            count += interval.second - interval.first + 1;
        }
        return count;
    }

private:
    vector<pair<int, int>>* intervals;
};
```

